1	import type { MarketAnalyticsSummary } from "@/lib/api/types";
2	import { formatCurrency } from "@/lib/utils/format";
3	
4	export function AnalyticsSummaryCards({
5	  summary,
6	}: {
7	  summary: MarketAnalyticsSummary;
8	}) {
9	  const cards = [
10	    {
11	      label: "Total Activity",
12	      value: summary.totalTrades.toLocaleString(),
13	      tone: "var(--color-text)",
14	    },
15	    {
16	      label: "Total Volume",
17	      value: formatCurrency(summary.totalVolume),
18	      tone: "var(--color-primary-hover)",
19	    },
20	    {
21	      label: "Unique Traders",
22	      value: summary.uniqueTraders.toLocaleString(),
23	      tone: "var(--color-success)",
24	    },
25	    {
26	      label: "Last Update",
27	      value: new Date(summary.lastUpdated).toLocaleString(),
28	      tone: "var(--color-text)",
29	    },
30	  ];
31	
32	  return (
33	    <div
34	      style={{
35	        display: "grid",
36	        gap: "var(--space-md)",
37	        gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))",
38	      }}
39	    >
40	      {cards.map((card) => (
41	        <div key={card.label} style={cardStyle}>
42	          <div style={labelStyle}>{card.label}</div>
43	          <div style={{ ...valueStyle, color: card.tone }}>{card.value}</div>
44	          {card.label === "Last Update" && (
45	            <div style={captionStyle}>
46	              Accepted activity freshness for the selected market.
47	            </div>
48	          )}
49	        </div>
50	      ))}
51	    </div>
52	  );
53	}
54	
55	const cardStyle: React.CSSProperties = {
56	  padding: "var(--space-md)",
57	  borderRadius: "var(--radius-md)",
58	  border: "1px solid var(--color-border)",
59	  background: "var(--color-bg-surface)",
60	  minHeight: 112,
61	};
62	
63	const labelStyle: React.CSSProperties = {
64	  fontSize: "0.74rem",
65	  fontWeight: 700,
66	  letterSpacing: "0.08em",
67	  textTransform: "uppercase",
68	  color: "var(--color-text-muted)",
69	  marginBottom: "var(--space-sm)",
70	};
71	
72	const valueStyle: React.CSSProperties = {
73	  fontSize: "1.25rem",
74	  fontWeight: 700,
75	};
76	
77	const captionStyle: React.CSSProperties = {
78	  marginTop: "var(--space-sm)",
79	  fontSize: "0.74rem",
80	  color: "var(--color-text-muted)",
81	};
