1	import { describe, it, expect } from "vitest";
2	import { formatProbability, formatCurrency, truncateHash, statusColor } from "@/lib/utils/format";
3	
4	describe("formatProbability", () => {
5	  it("formats 0.65 as 65.0%", () => expect(formatProbability(0.65)).toBe("65.0%"));
6	  it("formats 0.01 as 1.0%", () => expect(formatProbability(0.01)).toBe("1.0%"));
7	  it("formats 0.999 as 99.9%", () => expect(formatProbability(0.999)).toBe("99.9%"));
8	});
9	
10	describe("formatCurrency", () => {
11	  it("formats large numbers with K suffix", () => expect(formatCurrency(45000)).toBe("45.0K"));
12	  it("formats millions with M suffix", () => expect(formatCurrency(1500000)).toBe("1.5M"));
13	  it("formats small numbers with decimals", () => expect(formatCurrency(42.5)).toBe("42.50"));
14	});
15	
16	describe("truncateHash", () => {
17	  it("truncates sha256 hashes", () => {
18	    expect(truncateHash("sha256:abcdef0123456789")).toBe("sha256:abcdef01…");
19	  });
20	  it("leaves short strings alone", () => {
21	    expect(truncateHash("short")).toBe("short");
22	  });
23	});
24	
25	describe("statusColor", () => {
26	  it("returns green for active", () => expect(statusColor("active")).toBe("var(--color-active)"));
27	  it("returns blue for resolved", () => expect(statusColor("resolved")).toBe("var(--color-resolved)"));
28	  it("returns muted for unknown", () => expect(statusColor("unknown")).toBe("var(--color-text-muted)"));
29	});
30

1	import { describe, it, expect } from "vitest";
